SELECT 
FROM user

    is_deleted = 0
    AND account = #{user.account}
    AND nickname LIKE CONCAT('%', #{user.nickname}, '%')
    AND email = #{user.email}
    AND role = #{user.role}
    AND profile LIKE CONCAT('%', #{user.profile}, '%')

ORDER BY create_time DESC

SELECT COUNT(*)
FROM user

    is_deleted = 0
    AND account = #{user.account}
    AND nickname LIKE CONCAT('%', #{user.nickname}, '%')
    AND email = #{user.email}
    AND role = #{user.role}

SELECT 
FROM user

    is_deleted = 0
    AND id = #{request.id}
    AND account = #{request.account}
    AND nickname LIKE CONCAT('%', #{request.nickname}, '%')
    AND email = #{request.email}
    AND role = #{request.role}
    AND profile LIKE CONCAT('%', #{request.profile}, '%')




            ORDER BY ${request.sortField} DESC


            ORDER BY ${request.sortField} ASC




    ORDER BY create_time DESC
